BATCH_ID="B_CLASS_371_20260719"; BATCH_NUMBER=16; BATCH_NAME=f"{BATCH_ID}_MANUAL_{BATCH_NUMBER:03d}"
REPORT_ROOT = ROOT / "runs/extraction/B/batches" / BATCH_ID
REPORT_ROOT.mkdir(parents=True, exist_ok=True)
